JinjaTemplate:
{% set user_name = 'user' %}
{% set assistant_name = 'assistant' %}
{% set system_name = 'system' %}

{{ bos_token }}
{% for message in messages %}
    {% if message['role'] == 'user' %}
    {% set role = user_name %}
    {% endif %}
    {% if message['role'] == 'assistant' %}
    {% set role = assistant_name %}
    {% endif %}
    {% if message['role'] == 'system' %}
    {% set role = system_name %}
    {% endif %}

    {%- if not loop.last -%}
    {{ '<|start_header_id|>' + role + '<|end_header_id|>\n\n'+ message['content'] | trim + '<|eot_id|>' }}
    {%- endif -%}
    {% if loop.last -%}
        {% if role == assistant_name -%}
        {{ '<|start_header_id|>' + role + '<|end_header_id|>\n\n'+ message['content'] | trim }}
        {%- endif %}
        {% if role != assistant_name -%}
        {{ '<|start_header_id|>' + role + '<|end_header_id|>\n\n'+ message['content'] | trim + '<|eot_id|>' + '<|start_header_id|>'+assistant_name+'<|end_header_id|>\n\n' }}
        {%- endif %}
    {% endif %}
{% endfor %}
